create table if not exists public.airdrop_claims(id bigint generated by default as identity primary key,user_id bigint not null references public.users(id) on delete cascade,task_code text not null,coins numeric(20,0) not null check(coins>0),created_at timestamptz not null default now(),unique(user_id,task_code));
alter table public.airdrop_claims enable row level security;
create or replace function public.get_airdrop_balance(p_user_id bigint) returns numeric language sql security definer set search_path=public as $$ select least(10000::numeric,coalesce(sum(coins),0)) from public.airdrop_claims where user_id=p_user_id; $$;
create or replace function public.claim_airdrop_task(p_user_id bigint,p_task_code text) returns jsonb language plpgsql security definer set search_path=public as $$ declare v_coins numeric;v_total numeric;begin if p_task_code='registration' then v_coins:=1000;else raise exception 'TASK_VERIFICATION_NOT_READY';end if;insert into public.airdrop_claims(user_id,task_code,coins) values(p_user_id,p_task_code,v_coins) on conflict(user_id,task_code) do nothing;if not found then raise exception 'TASK_ALREADY_CLAIMED';end if;select least(10000::numeric,coalesce(sum(coins),0)) into v_total from public.airdrop_claims where user_id=p_user_id;return jsonb_build_object('success',true,'coins_added',v_coins,'total_coins',v_total,'message','Airdrop coins added. Coins are locked and non-withdrawable.');end;$$;
revoke all on function public.get_airdrop_balance(bigint) from public;revoke all on function public.claim_airdrop_task(bigint,text) from public;grant execute on function public.get_airdrop_balance(bigint) to anon,authenticated;grant execute on function public.claim_airdrop_task(bigint,text) to anon,authenticated;
select 'NET GAIN pre-launch airdrop backend installed' as result;